   187→void PluginManager::loadPlugin(const std::filesystem::path& libPath)
   188→{
   189→    if (!fs::exists(libPath))
   190→        throw MBSException(fmt::format("Plugin library '{}' does not exist", libPath.string()));
   191→
   192→    spdlog::info("Loading plugin '{}'", libPath.string());
   193→
   194→    auto handle = std::make_unique<PluginHandle>();
   195→    handle->dlHandle = openLibrary(libPath);
   196→
   197→    // Resolve factory functions
   198→    auto createFn  = loadSymbol<CreatePluginFn>(handle->dlHandle, CREATE_FN_NAME);
   199→    auto destroyFn = loadSymbol<DestroyPluginFn>(handle->dlHandle, DESTROY_FN_NAME);
   200→
   201→    // Create plugin instance
   202→    std::unique_ptr<IPlugin> pluginPtr(createFn());
   203→    if (!pluginPtr)
   204→        throw MBSException(fmt::format("Factory returned nullptr for plugin '{}'", libPath.string()));
   205→
   206→    // Bind custom deleter for smart pointer
   207→    pluginPtr = std::unique_ptr<IPlugin>(pluginPtr.release(), [destroyFn](IPlugin* p) {
   208→        if (!p) return;
   209→        try
   210→        {
   211→            destroyFn(p);
   212→        }
   213→        catch (...)
   214→        {
   215→            spdlog::warn("Exception thrown from plugin destroy function");
   216→        }
   217→    });
   218→
   219→    // Retrieve metadata, falling back to sidecar json, then IPlugin::metadata()
   220→    auto sidecar                 = loadSidecarMetadata(libPath);
   221→    handle->metadata             = sidecar.value_or(pluginPtr->metadata());
   222→    handle->instance             = std::move(pluginPtr);
   223→    handle->loadTimestamp        = clock::now();
   224→
   225→    // Register with event bus
   226→    handle->instance->subscribe(_eventBus);
   227→
   228→    // Telemetry
   229→    Telemetry::instance().emit("plugin.loaded", {
   230→        {"id", handle->metadata.id},
   231→        {"version", handle->metadata.version}
   232→    });
   233→
   234→    spdlog::info("Plugin '{}' (v{}) successfully loaded", handle->metadata.name, handle->metadata.version);
   235→    _handles.emplace_back(std::move(handle));
   236→}
