   238→void PluginManager::unloadPlugin(const std::string& pluginId)
   239→{
   240→    std::scoped_lock lk(_mutex);
   241→
   242→    const auto it = std::find_if(_handles.begin(), _handles.end(),
   243→                                 [&pluginId](const auto& h) { return h->metadata.id == pluginId; });
   244→
   245→    if (it == _handles.end())
   246→        throw MBSException(fmt::format("No plugin with id '{}' is loaded", pluginId));
   247→
   248→    auto& handle = *it;
   249→
   250→    spdlog::info("Unloading plugin '{}'", handle->metadata.name);
   251→
   252→    // Unsubscribe from bus first (prevent dangling callbacks)
   253→    handle->instance->unsubscribe(_eventBus);
   254→
   255→    // Destroy plugin instance (unique_ptr deleter)
   256→    handle->instance.reset();
   257→
   258→    // Close dynamic library
   259→    closeLibrary(handle->dlHandle);
   260→    handle->dlHandle = nullptr;
   261→
   262→    Telemetry::instance().emit("plugin.unloaded", {
   263→        {"id", pluginId}
   264→    });
   265→
   266→    _handles.erase(it);
   267→}
   268→
   269→void PluginManager::unloadAll()
   270→{
   271→    std::scoped_lock lk(_mutex);
   272→    while (!_handles.empty())
   273→        unloadPlugin(_handles.front()->metadata.id);
   274→}
