   276→bool PluginManager::isLoaded(const std::filesystem::path& libPath) const
   277→{
   278→    const auto canonicalized = fs::weakly_canonical(libPath);
   279→
   280→    return std::any_of(_handles.begin(), _handles.end(), [&](const auto& h) {
   281→        return fs::weakly_canonical(h->metadata.libraryPath) == canonicalized;
   282→    });
   283→}
