   286→{
   287→    std::scoped_lock lk(_mutex);
   288→    std::vector<PluginMetadata> metas;
   289→    metas.reserve(_handles.size());
   290→    for (const auto& h : _handles)
   291→        metas.push_back(h->metadata);
   292→    return metas;
   293→}
