   295→/* -------------------------------------------------------------------------- */
   296→/*                               Hot Reloading                                */
   297→/* -------------------------------------------------------------------------- */
   298→
   299→bool PluginManager::reloadIfChanged()
   300→{
   301→    std::scoped_lock lk(_mutex);
   302→    bool anyReloaded = false;
   303→
   304→    for (auto& handle : _handles)
   305→    {
   306→        const auto now          = fs::last_write_time(handle->metadata.libraryPath);
   307→        const auto loadedAt     = handle->loadTimestamp;
   308→
   309→        if (now > loadedAt)
   310→        {
   311→            spdlog::info("Change detected in plugin '{}', reloading...", handle->metadata.name);
   312→            const auto id = handle->metadata.id;
   313→            try
   314→            {
   315→                unloadPlugin(id);
   316→                loadPlugin(handle->metadata.libraryPath);
   317→                anyReloaded = true;
   318→            }
   319→            catch (std::exception& ex)
   320→            {
   321→                spdlog::error("Hot-reload failed for plugin '{}': {}", id, ex.what());
   322→            }
   323→        }
   324→    }
   325→    return anyReloaded;
   326→}
