    24→*      struct DataArrived { std::string channel; nlohmann::json payload; };
    25→*      auto token = EventBus::instance().subscribe<DataArrived>(
    26→*          [](const DataArrived& ev) { /* … */ },
    27→*          EventDelivery::Async);   // or EventDelivery::Sync
    28→*
    29→*      EventBus::instance().publish<DataArrived>({"metrics", json::parse("{}")});
