    60→/*---------------------------------------------*
    61→ *               Subscription Token             *
    62→ *---------------------------------------------*/
    63→/**
    64→ * An opaque handle that represents a subscription registration.
    65→ * When the token is destroyed, it automatically unregisters the
    66→ * listener from the EventBus to avoid dangling callbacks.
    67→ */
    68→class SubscriptionToken {
    69→public:
    70→    SubscriptionToken() = default;
    71→    SubscriptionToken(const SubscriptionToken&)            = delete;
    72→    SubscriptionToken& operator=(const SubscriptionToken&) = delete;
    73→
    74→    SubscriptionToken(SubscriptionToken&& rhs) noexcept { moveFrom(std::move(rhs)); }
    75→    SubscriptionToken& operator=(SubscriptionToken&& rhs) noexcept {
    76→        if (this != &rhs) {
    77→            unsubscribe();
    78→            moveFrom(std::move(rhs));
    79→        }
    80→        return *this;
    81→    }
    82→
    83→    ~SubscriptionToken() { unsubscribe(); }
    84→
    85→private:
    86→    friend class EventBus;
    87→
    88→    explicit SubscriptionToken(std::weak_ptr<void> controlBlock,
    89→                               std::function<void()>   onUnsubscribe)
    90→        : m_control(std::move(controlBlock))
    91→        , m_onUnsubscribe(std::move(onUnsubscribe)) {}
    92→
    93→    void unsubscribe() {
    94→        if (auto locked = m_control.lock()) {  // still valid
    95→            if (m_onUnsubscribe) {
    96→                try { m_onUnsubscribe(); }
    97→                catch (const std::exception& ex) {
    98→                    spdlog::error("Exception while unsubscribing: {}", ex.what());
    99→                }
   100→            }
   101→        }
   102→        m_control.reset();
   103→        m_onUnsubscribe = nullptr;
   104→    }
   105→
   106→    void moveFrom(SubscriptionToken&& other) {
   107→        m_control       = std::move(other.m_control);
   108→        m_onUnsubscribe = std::move(other.m_onUnsubscribe);
   109→        other.m_control.reset();
   110→        other.m_onUnsubscribe = nullptr;
   111→    }
   112→
   113→    std::weak_ptr<void>   m_control;
   114→    std::function<void()> m_onUnsubscribe;
   115→};
