   120→class ThreadPool final {
   121→public:
   122→    explicit ThreadPool(std::size_t workers = std::thread::hardware_concurrency())
   123→        : m_shutdown(false) {
   124→        workers = std::max<std::size_t>(1, workers);
   125→        for (std::size_t i = 0; i < workers; ++i) {
   126→            m_threads.emplace_back([this] { workerLoop(); });
   127→        }
   128→    }
   129→
   130→    ThreadPool(const ThreadPool&)            = delete;
   131→    ThreadPool& operator=(const ThreadPool&) = delete;
   132→
   133→    ~ThreadPool() {
   134→        {
   135→            std::unique_lock lk(m_mutex);
   136→            m_shutdown = true;
   137→        }
   138→        m_cv.notify_all();
   139→        for (auto& t : m_threads)
   140→            if (t.joinable()) t.join();
   141→    }
   142→
   143→    template <typename Fn>
   144→    void enqueue(Fn&& fn) {
   145→        {
   146→            std::unique_lock lk(m_mutex);
   147→            m_tasks.emplace(std::forward<Fn>(fn));
   148→        }
   149→        m_cv.notify_one();
   150→    }
   151→
   152→private:
   153→    void workerLoop() {
   154→        while (true) {
   155→            std::function<void()> task;
   156→            {
   157→                std::unique_lock lk(m_mutex);
   158→                m_cv.wait(lk, [this] { return m_shutdown || !m_tasks.empty(); });
   159→                if (m_shutdown && m_tasks.empty()) return;
   160→                task = std::move(m_tasks.front());
   161→                m_tasks.pop();
   162→            }
   163→            try { task(); }
   164→            catch (const std::exception& ex) {
   165→                spdlog::error("Unhandled exception in ThreadPool task: {}", ex.what());
   166→            }
   167→        }
   168→    }
   169→
   170→    std::vector<std::thread>  m_threads;
   171→    std::queue<std::function<void()>> m_tasks;
   172→    std::mutex                m_mutex;
   173→    std::condition_variable   m_cv;
   174→    bool                      m_shutdown;
   175→};
