   207→    [[nodiscard]] SubscriptionToken subscribe(
   208→        std::function<void(const EventT&)> callback,
   209→        EventDelivery                      delivery = EventDelivery::Async) {
   210→        static_assert(std::is_copy_constructible_v<EventT>,
   211→                      "Event type must be copy constructible");
   212→        static_assert(std::is_move_constructible_v<EventT>,
   213→                      "Event type must be move constructible");
