   219→        {
   220→            std::unique_lock lk(m_subscriberMutex);
   221→            auto& bucket = m_subscribers[ti];
   222→            bucket.emplace_back(subscriber);
   223→        }
   224→
   225→        auto removalFn = [this, ti, weak = std::weak_ptr<void>(subscriber)] {
   226→            std::unique_lock lk(m_subscriberMutex);
   227→            auto it = m_subscribers.find(ti);
   228→            if (it == m_subscribers.end()) return;
   229→
   230→            auto& vec = it->second;
