   232→                                     vec.end(),
   233→                                     [&](const std::shared_ptr<BaseSubscriber>& ptr) {
   234→                                         return ptr == weak.lock();
   235→                                     }),
   236→                      vec.end());
   237→        };
   238→
   239→        return SubscriptionToken{subscriber, std::move(removalFn)};
