    95→/* ──────────────────────────────────────────────────────────────────────────── */
    96→/*                                  EventBus                                   */
    97→/*        (simple in-process pub/sub mechanics – threadsafe, copyable)         */
    98→/* ──────────────────────────────────────────────────────────────────────────── */
    99→
   100→class EventBus
   101→{
   102→public:
   103→    using Topic     = std::string;
   104→    using Payload   = json;
   105→    using Callback  = std::function<void(const Payload&)>;
   106→
   107→    void subscribe(const Topic& t, Callback cb)
   108→    {
   109→        std::lock_guard lg{ _mx };
   110→        _subscribers[t].push_back(std::move(cb));
   111→    }
   112→
   113→    void publish(const Topic& t, const Payload& p) const
   114→    {
   115→        std::vector<Callback> cbs;
   116→        {
   117→            std::lock_guard lg{ _mx };
   118→            if (auto found = _subscribers.find(t); found != _subscribers.end())
   119→                cbs = found->second;
   120→        }
   121→        for (auto& cb : cbs)
   122→        {
   123→            try       { cb(p); }
   124→            catch (...) { spdlog::error("EventBus callback on topic '{}' failed", t); }
   125→        }
   126→    }
   127→
   128→private:
   129→    mutable std::mutex _mx;
   130→    std::unordered_map<Topic, std::vector<Callback>> _subscribers;
   131→};
