   134→/* ──────────────────────────────────────────────────────────────────────────── */
   135→/*                              Plugin Manager                                 */
   136→/* ──────────────────────────────────────────────────────────────────────────── */
   137→
   138→struct TileInfo
   139→{
   140→    std::string id;
   141→    std::string name;
   142→    std::string version;
   143→    json        meta;
   144→};
   145→
   146→/**
   147→ *  The shared-lib side is expected to expose a "C" factory symbol with the
   148→ *  signature:
   149→ *
   150→ *      extern "C"
   151→ *      bool registerTile(std::function<void(const TileInfo&, std::function<json(const json&)>)>);
   152→ *
   153→ *  The function receives a callback that the plugin uses to register itself.
   154→ */
   155→using TileCallback    = std::function<json(const json&)>;
   156→using RegisterTileSig = bool(*)(std::function<void(const TileInfo&, TileCallback)>);
   157→
   158→class PluginManager
   159→{
   160→public:
   161→    explicit PluginManager(EventBus& bus)
   162→    : _bus(bus)
   163→    {}
   164→
   165→    void discover(const fs::path& dir)
   166→    {
   167→        if (!fs::exists(dir) || !fs::is_directory(dir))
   168→        {
   169→            spdlog::warn("Plugin directory '{}' not found.", dir.string());
   170→            return;
   171→        }
   172→
   173→        for (auto& entry : fs::directory_iterator(dir))
   174→        {
   175→            if (!entry.is_regular_file()) continue;
   176→
   177→            auto path = entry.path();
   178→            if (path.extension() != ".so" && path.extension() != ".dylib")
   179→                continue; // only loading Unix-like shared libraries
   180→
   181→            try { loadLibrary(path); }
   182→            catch (const std::exception& ex)
   183→            {
   184→                spdlog::error("Plugin load failed ({}): {}", path.string(), ex.what());
   185→            }
   186→        }
   187→    }
   188→
   189→    std::vector<TileInfo> listTiles() const
   190→    {
   191→        std::lock_guard lg{ _mx };
   192→        std::vector<TileInfo> v;
   193→        v.reserve(_tiles.size());
   194→        for (auto& [id, pair] : _tiles) v.push_back(pair.first);
   195→        return v;
   196→    }
   197→
   198→    std::optional<json> invokeTile(const std::string& id, const json& payload)
   199→    {
   200→        std::lock_guard lg{ _mx };
   201→        auto it = _tiles.find(id);
   202→        if (it == _tiles.end()) return std::nullopt;
   203→
   204→        return it->second.second(payload);
   205→    }
   206→
   207→    ~PluginManager()
   208→    {
   209→        for (auto handle : _handles) dlclose(handle);
   210→    }
   211→
   212→private:
   213→    void loadLibrary(const fs::path& path)
   214→    {
   215→        void* handle = dlopen(path.c_str(), RTLD_NOW);
   216→        if (!handle)
   217→            throw std::runtime_error(dlerror());
   218→
   219→        auto reg = (RegisterTileSig)dlsym(handle, "registerTile");
   220→        if (!reg)
   221→        {
   222→            dlclose(handle);
   223→            spdlog::warn("Shared library {} missing registerTile symbol.", path.string());
   224→            return;
   225→        }
   226→
   227→        bool ok = reg([this](const TileInfo& info, TileCallback cb) {
   228→            std::lock_guard lg{ _mx };
   229→            if (_tiles.contains(info.id))
   230→                throw std::runtime_error("Duplicate tile id: " + info.id);
   231→            _tiles.emplace(info.id, std::make_pair(info, std::move(cb)));
   232→            spdlog::info("Tile registered: {} (v{})", info.name, info.version);
   233→            _bus.publish("tiles/registered", { {"id", info.id}, {"name", info.name} });
   234→        });
   235→
   236→        if (!ok)
   237→            throw std::runtime_error("Plugin registration reported failure.");
   238→
   239→        _handles.push_back(handle);
   240→        spdlog::info("Loaded plugin '{}'", path.filename().string());
   241→    }
   242→
   243→    EventBus& _bus;
   244→    mutable std::mutex _mx;
   245→
   246→    std::unordered_map<std::string, std::pair<TileInfo, TileCallback>> _tiles;
   247→    std::vector<void*> _handles;
   248→};
