   251→/* ──────────────────────────────────────────────────────────────────────────── */
   252→/*                              Application Core                               */
   253→/* ──────────────────────────────────────────────────────────────────────────── */
   254→
   255→class MosaicBoardApp
   256→{
   257→public:
   258→    MosaicBoardApp(AppConfig cfg)
   259→      : _cfg(std::move(cfg)),
   260→        _logger(initLogger(_cfg)),
   261→        _pluginManager(_bus)
   262→    {}
   263→
   264→    void run()
   265→    {
   266→        spdlog::info("Booting MosaicBoard Studio…");
   267→
   268→        // Discover plugins
   269→        _pluginManager.discover(_cfg.pluginsDir);
   270→        spdlog::info("Discovered {} tiles", _pluginManager.listTiles().size());
   271→
   272→        // Wire internal event bus handlers, example:
   273→        _bus.subscribe("tiles/registered", [](const json& payload){
   274→            spdlog::info("Event: new tile registered -> {}", payload.dump());
   275→        });
   276→
   277→        // Build REST API
   278→        initRoutes();
   279→
   280→        // Signal handling for graceful shutdown
   281→        std::signal(SIGINT,  signalHandler);
   282→        std::signal(SIGTERM, signalHandler);
   283→
   284→        // Start server (blocking call)
   285→        _server.bindaddr(_cfg.httpAddress)
   286→               .port(_cfg.httpPort)
   287→               .multithreaded()
   288→               .run();
   289→    }
   290→
   291→private:
   292→    /* Logging ----------------------------------------------------------------*/
   293→
   294→    static std::shared_ptr<spdlog::logger> initLogger(const AppConfig& cfg)
   295→    {
   296→        try
   297→        {
   298→            auto sink = std::make_shared<spdlog::sinks::rotating_file_sink_mt>(
   299→                cfg.logFile, cfg.logFileSize, cfg.logFiles
   300→            );
   301→            auto logger = std::make_shared<spdlog::logger>("MosaicBoard", sink);
   302→            logger->set_pattern("[%Y-%m-%d %H:%M:%S] [%l] %v");
   303→            spdlog::set_default_logger(logger);
   304→            spdlog::flush_on(spdlog::level::info);
   305→            return logger;
   306→        }
   307→        catch (const spdlog::spdlog_ex& ex)
   308→        {
   309→            throw std::runtime_error("Logger init failed: " + std::string(ex.what()));
   310→        }
   311→    }
   312→
   313→    /* REST/API routes --------------------------------------------------------*/
   314→
   315→    void initRoutes()
   316→    {
   317→        // Health
   318→        CROW_ROUTE(_server, "/api/v1/health")
   319→        .methods("GET"_method)
   320→        ([]{
   321→            json payload = { {"status", "ok"}, {"ts", std::chrono::system_clock::to_time_t(std::chrono::system_clock::now())} };
   322→            return crow::response{ payload.dump() };
   323→        });
   324→
   325→        // List tiles
   326→        CROW_ROUTE(_server, "/api/v1/tiles")
   327→        .methods("GET"_method)
   328→        ([this]{
   329→            json arr = json::array();
   330→            for (auto& t : _pluginManager.listTiles()) {
   331→                arr.push_back({ {"id", t.id}, {"name", t.name}, {"version", t.version}, {"meta", t.meta} });
   332→            }
   333→            return crow::response{ arr.dump() };
   334→        });
   335→
   336→        // Invoke tile action
   337→        CROW_ROUTE(_server, "/api/v1/tiles/<string>/action")
   338→        .methods("POST"_method)
   339→        ([this](const std::string& id, const crow::request& req){
   340→            try
   341→            {
   342→                auto payload = json::parse(req.body.empty() ? "{}" : req.body);
   343→                auto res     = _pluginManager.invokeTile(id, payload);
   344→                if (!res) return crow::response(404, "Tile not found");
   345→
   346→                return crow::response{ res->dump() };
   347→            }
   348→            catch (const std::exception& ex)
   349→            {
   350→                spdlog::error("Tile invocation failed: {}", ex.what());
   351→                return crow::response(500, "Internal server error");
   352→            }
   353→        });
   354→
   355→        // WebSocket endpoint for real-time events
   356→        CROW_ROUTE(_server, "/ws")
   357→        .websocket()
   358→        .onopen([this](crow::websocket::connection& conn){
   359→            _wsConnections.insert(&conn);
   360→            spdlog::info("WebSocket client connected ({} connections total)", _wsConnections.size());
   361→        })
   362→        .onclose([this](crow::websocket::connection& conn, const std::string& reason){
   363→            _wsConnections.erase(&conn);
   364→            spdlog::info("WebSocket client disconnected: {}", reason);
   365→        })
   366→        .onmessage([this](crow::websocket::connection& conn, const std::string& msg, bool is_bin){
   367→            if (is_bin) return;
   368→            try {
   369→                auto j = json::parse(msg);
   370→                if (j.contains("subscribe"))
   371→                {
   372→                    std::string topic = j["subscribe"];
   373→                    _bus.subscribe(topic, [&conn](const json& event){
   374→                        if (conn.is_open())
   375→                            conn.send_text(event.dump());
   376→                    });
   377→                }
   378→            } catch(...) {}
   379→        });
   380→    }
   381→
   382→    /* Static signal handler --------------------------------------------------*/
   383→
   384→    static void signalHandler(int sig)
   385→    {
   386→        if (sig == SIGINT || sig == SIGTERM)
   387→        {
   388→            spdlog::info("Shutdown requested (signal {}).", sig);
   389→            _shutdownRequested.store(true);
   390→        }
   391→    }
   392→
   393→private:
   394→    AppConfig                                _cfg;
   395→    std::shared_ptr<spdlog::logger>          _logger;
   396→    EventBus                                 _bus;
   397→    PluginManager                            _pluginManager;
   398→    crow::SimpleApp                          _server;
   399→
   400→    std::unordered_set<crow::websocket::connection*> _wsConnections;
   401→
   402→    static inline std::atomic<bool> _shutdownRequested{false};
   403→};
