    68→// =================================================================================================
    69→// Internal helpers – lightweight 1-D value noise implementation
    70→// =================================================================================================
    71→namespace
    72→{
    73→class ValueNoise
    74→{
    75→public:
    76→    explicit ValueNoise(std::uint32_t seed = std::random_device{}())
    77→        : m_seed(seed),
    78→          m_distribution(0.0f, 1.0f)
    79→    {
    80→        m_rng.seed(m_seed);
    81→    }
    82→
    83→    // Generates smooth pseudo-random value between 0 and 1 for a given position.
    84→    // Uses simple linear interpolation of two hashed lattice points.
    85→    float operator()(float x)
    86→    {
    87→        const int   xi0 = static_cast<int>(std::floor(x));
    88→        const int   xi1 = xi0 + 1;
    89→        const float xf  = x - static_cast<float>(xi0);
    90→
    91→        const float v0 = lattice(xi0);
    92→        const float v1 = lattice(xi1);
    93→
    94→        // Smoothstep interpolation
    95→        const float t  = xf * xf * (3.f - 2.f * xf);
    96→        return lerp(v0, v1, t);
    97→    }
    98→
    99→private:
   100→    float lattice(int xi)
   101→    {
   102→        std::mt19937 rng(static_cast<std::uint32_t>(xi) ^ m_seed);
   103→        return m_distribution(rng);
   104→    }
   105→
   106→    static float lerp(float a, float b, float t) { return a + (b - a) * t; }
   107→
   108→    std::uint32_t                     m_seed;
   109→    std::mt19937                      m_rng;
   110→    std::uniform_real_distribution<float> m_distribution;
   111→};
