   117→class GenerativeArtTile final : public Tile
   118→{
   119→public:
   120→    GenerativeArtTile()
   121→        : m_logger(Logger::acquire("GenerativeArtTile")),
   122→          m_eventBus(EventBus::instance()),
   123→          m_rng(std::random_device{}()),
   124→          m_colourDist(0, 255)
   125→    {
   126→        m_logger->info("GenerativeArtTile instantiated.");
