   134→    // ---------------------------------------------------------------------------------------------
   135→    // Tile lifecycle
   136→    // ---------------------------------------------------------------------------------------------
   137→    void prepare(const json& config) override
   138→    {
   139→        // Parse configuration with fallback values.
   140→        try
   141→        {
   142→            m_width       = config.value("width",  800);
   143→            m_height      = config.value("height", 600);
   144→            m_seed        = config.value("seed",  static_cast<std::uint32_t>(std::random_device{}()));
   145→            m_frameRate   = config.value("fps",   30);
   146→            m_paletteName = config.value("palette", "default");
   147→
   148→            m_valueNoise  = std::make_unique<ValueNoise>(m_seed);
   149→
   150→            m_logger->info("Tile prepared – size = {}x{}, fps = {}, seed = {}, palette = {}",
   151→                           m_width, m_height, m_frameRate, m_seed, m_paletteName);
   152→        }
   153→        catch (const std::exception& ex)
   154→        {
   155→            m_logger->error("Failed to parse configuration: {}", ex.what());
   156→            throw;  // Rethrow – host is responsible for bubbling up initialization failures.
   157→        }
   158→    }
   159→
   160→    json render() override
   161→    {
   162→        // Build an SVG string on the fly.
   163→        const auto startTime = HighResClock::now();
   164→
   165→        std::ostringstream oss;
   166→        oss << "<svg xmlns='http://www.w3.org/2000/svg' width='" << m_width
   167→            << "' height='" << m_height << "' viewBox='0 0 " << m_width << " " << m_height << "'>";
   168→        oss << "<rect width='100%' height='100%' fill='black'/>";
   169→
   170→        const std::size_t lines = 120;
   171→        const float       step  = static_cast<float>(m_width) / static_cast<float>(lines - 1);
   172→
   173→        for (std::size_t i = 0; i < lines; ++i)
   174→        {
   175→            const float t  = static_cast<float>(i) / static_cast<float>(lines);
   176→            const float y  = m_height * m_valueNoise->operator()(t * 3.0f);
   177→
   178→            const std::uint8_t r = static_cast<std::uint8_t>(m_colourDist(m_rng));
   179→            const std::uint8_t g = static_cast<std::uint8_t>(m_colourDist(m_rng));
   180→            const std::uint8_t b = static_cast<std::uint8_t>(m_colourDist(m_rng));
   181→
   182→            oss << "<line x1='" << i * step << "' y1='" << y
   183→                << "' x2='" << (i + 1) * step << "' y2='" << m_height - y
   184→                << "' stroke='rgb(" << static_cast<int>(r) << ","
   185→                                    << static_cast<int>(g) << ","
   186→                                    << static_cast<int>(b) << ")' "
   187→                << "stroke-width='2' stroke-linecap='round'/>";
   188→        }
   189→
   190→        oss << "</svg>";
   191→
   192→        const auto endTime = HighResClock::now();
   193→        const auto durationMs =
   194→            std::chrono::duration_cast<Milliseconds>(endTime - startTime).count();
   195→
   196→        // Publish render-time metric.
   197→        m_eventBus.publish(Event{
   198→            .topic   = "tile.metrics.render_time",
   199→            .payload = json{
   200→                {"tile_id", id()},
   201→                {"duration_ms", durationMs}
   202→            }
   203→        });
   204→
   205→        return json{
   206→            {"type", "svg"},
   207→            {"content", oss.str()},
   208→            {"render_time_ms", durationMs}
   209→        };
   210→    }
