   212→    void onEvent(const Event& event) override
   213→    {
   214→        if (event.topic == "global.ping")
   215→        {
   216→            m_logger->debug("Responding to global ping – tile_id={}", id());
   217→            m_eventBus.publish(Event{
   218→                .topic   = "tile.pong",
   219→                .payload = json{{"tile_id", id()}}
   220→            });
   221→        }
   222→        else if (event.topic == "tile.control.shuffle_palette" &&
   223→                 event.payload.value("tile_id", id()) == id())
   224→        {
   225→            shufflePalette();
   226→        }
   227→    }
