   230→    // Metadata
   231→    // ---------------------------------------------------------------------------------------------
   232→    std::string name() const noexcept override   { return "Generative Art Tile"; }
   233→    std::string category() const noexcept override { return "Generative"; }
   234→    Version     version() const noexcept override { return Version{1, 2, 0}; }
   235→
   236→private:
   237→    // Randomly changes colour distribution to create a new palette.
   238→    void shufflePalette()
   239→    {
   240→        std::uniform_int_distribution<std::uint32_t> seedDist;
   241→        m_seed = seedDist(m_rng);
   242→        m_valueNoise = std::make_unique<ValueNoise>(m_seed);
   243→
   244→        m_logger->info("Palette shuffled – new seed = {}", m_seed);
