   261→    std::uint32_t                  m_seed        = 0;
   262→    int                            m_frameRate   = 30;
   263→    std::string                    m_paletteName = "default";
   264→
   265→    // Runtime objects
   266→    std::unique_ptr<ValueNoise>    m_valueNoise;
   267→    std::mt19937                   m_rng;
   268→    std::uniform_int_distribution<int> m_colourDist;
   269→};
