   281→#   endif
   282→#endif
   283→
   284→// Called automatically by the host when the shared library is loaded.
   285→MBS_PLUGIN_API void register_plugin(mbs::plugin::PluginRegistry& registry)
   286→{
   287→    static const std::string kPluginName = "example_generative_art";
   288→    Logger logger = Logger::acquire("GenerativeArtPluginEntry");
   289→
   290→    try
   291→    {
   292→        registry.addPlugin({
   293→            .name        = kPluginName,
   294→            .version     = Version{1, 0, 0},
   295→            .description = "Procedurally generates SVG lines based on value noise.",
   296→            .author      = "MosaicBoard Studio",
   297→            .repository  = "https://github.com/mosaicboard-studio/example_generative_art"
   298→        });
   299→
   300→        registry.registerTileFactory(
   301→            kPluginName,
   302→            []() -> TilePtr {
   303→                return std::make_unique<GenerativeArtTile>();
   304→            });
   305→
   306→        logger->info("Plugin '{}' registered successfully.", kPluginName);
   307→    }
   308→    catch (const std::exception& ex)
   309→    {
   310→        logger->critical("Failed to register plugin '{}': {}", kPluginName, ex.what());
   311→        throw;  // Fatal – host will unload the shared library.
   312→    }
   313→}
