    54→public:
    55→    explicit Impl(const Options &opts)
    56→        : opts_{opts},
    57→          ioc_{static_cast<int>(opts.threadCount)},
    58→          acceptor_{ioc_},
    59→          sslCtx_{boost::asio::ssl::context::tls_server},
    60→          signals_{ioc_}
    61→    {
    62→        configureSignals();
    63→        configureSSL();
