    76→    void start()
    77→    {
    78→        if (running_.exchange(true)) { return; }    // Already running
    79→        doAccept();
    80→
    81→        // Spawn worker threads
    82→        workerThreads_.reserve(opts_.threadCount);
    83→        for (std::size_t i = 0; i < opts_.threadCount; ++i)
    84→        {
    85→            workerThreads_.emplace_back([this] {
    86→                spdlog::debug("Worker thread {} started.", std::this_thread::get_id());
    87→                ioc_.run();
    88→            });
    89→        }
    90→
    91→        spdlog::info("Server started with {} worker threads.", opts_.threadCount);
    92→    }
    93→
    94→    void stop()
    95→    {
    96→        if (!running_.exchange(false)) { return; }    // Already stopped
    97→        spdlog::info("Stopping server...");
    98→
    99→        boost::system::error_code ec;
   100→        acceptor_.cancel(ec);
   101→        acceptor_.close(ec);
   102→
   103→        ioc_.stop();
   104→        for (auto &t : workerThreads_)
   105→        {
   106→            if (t.joinable()) { t.join(); }
   107→        }
   108→        workerThreads_.clear();
   109→
   110→        spdlog::info("Server stopped.");
   111→    }
