   167→    void configureSignals()
   168→    {
   169→        signals_.add(SIGINT);
   170→        signals_.add(SIGTERM);
   171→#if defined(SIGQUIT)
   172→        signals_.add(SIGQUIT);
   173→#endif
   174→        signals_.async_wait([this](const boost::system::error_code & /*ec*/, int /*signo*/) {
   175→            spdlog::warn("Shutdown signal received.");
   176→            stop();
   177→        });
   178→    }
   179→
   180→    void configureSSL()
   181→    {
   182→        if (!opts_.useSSL) { return; }
   183→
   184→        sslCtx_.set_options(
   185→            boost::asio::ssl::context::default_workarounds
   186→            | boost::asio::ssl::context::no_sslv2
   187→            | boost::asio::ssl::context::single_dh_use);
   188→
   189→        sslCtx_.use_certificate_chain_file(opts_.certFile);
   190→        sslCtx_.use_private_key_file(opts_.keyFile, boost::asio::ssl::context::file_format::pem);
   191→    }
