   193→    void openAcceptor()
   194→    {
   195→        boost::system::error_code ec;
   196→
   197→        tcp::endpoint endpoint{boost::asio::ip::make_address(opts_.address, ec), opts_.port};
   198→        if (ec)
   199→        {
   200→            throw std::runtime_error{"Invalid address: " + ec.message()};
   201→        }
   202→
   203→        acceptor_.open(endpoint.protocol(), ec);
   204→        if (ec) { throw std::runtime_error{"Open error: " + ec.message()}; }
   205→
   206→        acceptor_.set_option(boost::asio::socket_base::reuse_address(true));
   207→        acceptor_.bind(endpoint, ec);
   208→        if (ec) { throw std::runtime_error{"Bind error: " + ec.message()}; }
   209→
   210→        acceptor_.listen(boost::asio::socket_base::max_listen_connections, ec);
   211→        if (ec) { throw std::runtime_error{"Listen error: " + ec.message()}; }
   212→    }
   213→
   214→    void doAccept()
   215→    {
   216→        acceptor_.async_accept([this](boost::system::error_code ec, tcp::socket socket) {
   217→            if (!ec)
   218→            {
   219→                spdlog::trace("Incoming connection from {}", socket.remote_endpoint());
   220→                std::make_shared<HTTPSession>(std::move(socket), opts_.useSSL ? &sslCtx_ : nullptr,
   221→                                              [this](string_req &&req) { return dispatch(std::move(req)); })
   222→                    ->run();
   223→            }
   224→            else
   225→            {
   226→                spdlog::error("Accept error: {}", ec.message());
   227→            }
   228→
   229→            if (isRunning()) { doAccept(); }
   230→        });
   231→    }
