   242→    string_res dispatch(string_req &&req)
   243→    {
   244→        try
   245→        {
   246→            auto target = std::string_view{req.target().data(), req.target().size()};
   247→            auto it     = routes_.find(target);
   248→            if (it != routes_.end())
   249→            {
   250→                return it->second(req);
   251→            }
   252→            return notFound(req);
   253→        }
   254→        catch (const std::exception &ex)
   255→        {
   256→            return serverError(req, ex.what());
   257→        }
   258→    }
